import { authkitProxy } from "@workos-inc/authkit-nextjs";
import { NextRequest, NextResponse } from "next/server";
import { authEnabled } from "@/lib/auth-config";

// Only initialize WorkOS proxy when auth is actually enabled.
// Initializing authkitProxy unconditionally sets internal WorkOS state that
// causes withAuth() to throw on every server action even when authEnabled=false.
const workosProxy = authEnabled
  ? authkitProxy({
      middlewareAuth: {
        enabled: true,
        unauthenticatedPaths: [
          "/",
          "/api/auth/callback",
          "/api/auth/sign-in",
          "/api/auth/sign-up",
        ],
      },
    })
  : null;

// In local/dev mode with DEV_AUTH_ENABLED=true, pass all requests through.
export default function proxy(
  request: NextRequest,
  context: Parameters<NonNullable<typeof workosProxy>>[1],
) {
  if (!authEnabled || !workosProxy) {
    return NextResponse.next();
  }
  return workosProxy(request, context);
}

export const config = {
  matcher: ["/((?!_next/static|_next/image|favicon.ico|images/).*)"],
};
